import { useState } from "react";
import { useTranslation } from "react-i18next";
import { useAuth } from "@/contexts/AuthContext";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Building2, Loader2 } from "lucide-react";
import { BrandFormDialog } from "@/components/admin/BrandFormDialog";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { Brand, ContentBlock } from "@/hooks/useBrands";
import { toast } from "sonner";
import { Json } from "@/integrations/supabase/types";

const parseContentBlocks = (json: Json | null): ContentBlock[] | null => {
  if (!json || !Array.isArray(json)) return null;
  return json as unknown as ContentBlock[];
};

const MerchantBrand = () => {
  const { t } = useTranslation();
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const { getLocalizedField } = useLocalizedContent();

  // Get merchant's restaurants
  const { data: merchantRestaurantIds = [] } = useQuery({
    queryKey: ["merchantRestaurantIds", user?.id],
    queryFn: async () => {
      if (!user) return [];
      const { data, error } = await supabase
        .from("merchant_restaurants")
        .select("restaurant_id")
        .eq("user_id", user.id);
      if (error) throw error;
      return data.map((r) => r.restaurant_id);
    },
    enabled: !!user,
  });

  // Get merchant's brand (check if any of their restaurants has a brand)
  const { data: merchantBrand, isLoading } = useQuery({
    queryKey: ["merchantBrand", user?.id],
    queryFn: async () => {
      if (!user) return null;

      // First check restaurants for existing brand_id
      const { data: restaurants } = await supabase
        .from("restaurants")
        .select("brand_id")
        .in("id", merchantRestaurantIds)
        .not("brand_id", "is", null)
        .limit(1);

      if (restaurants && restaurants.length > 0 && restaurants[0].brand_id) {
        const { data: brand } = await supabase
          .from("brands")
          .select("*")
          .eq("id", restaurants[0].brand_id)
          .single();
        if (brand) {
          return {
            ...brand,
            content_blocks: parseContentBlocks(brand.content_blocks),
          } as Brand;
        }
      }
      return null;
    },
    enabled: !!user && merchantRestaurantIds.length > 0,
  });

  // Auto-link brand to all merchant's restaurants
  const linkBrandToRestaurants = useMutation({
    mutationFn: async (brandId: string) => {
      if (merchantRestaurantIds.length === 0) return;
      const { error } = await supabase
        .from("restaurants")
        .update({ brand_id: brandId, is_chain: true })
        .in("id", merchantRestaurantIds);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["merchantBrand"] });
      queryClient.invalidateQueries({ queryKey: ["merchantRestaurants"] });
    },
  });

  if (isLoading) {
    return (
      <div className="flex justify-center items-center min-h-[50vh]">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-bold mb-2">
            {t("merchant.brand.title", "我的品牌")}
          </h1>
          <p className="text-muted-foreground">
            {t("merchant.brand.subtitle", "管理您的品牌信息，品牌将自动关联到您的所有商店")}
          </p>
        </div>
      </div>

      {merchantBrand ? (
        <Card className="overflow-hidden">
          {merchantBrand.image_url && (
            <div className="aspect-video overflow-hidden">
              <img
                src={merchantBrand.image_url}
                alt={merchantBrand.name}
                className="w-full h-full object-cover"
              />
            </div>
          )}
          <CardHeader className="pb-2">
            <div className="flex items-center gap-3">
              {merchantBrand.logo_url ? (
                <img
                  src={merchantBrand.logo_url}
                  alt={`${merchantBrand.name} logo`}
                  className="w-12 h-12 object-contain rounded-lg bg-muted p-1"
                />
              ) : (
                <div className="w-12 h-12 rounded-lg bg-primary/10 flex items-center justify-center">
                  <Building2 className="w-6 h-6 text-primary" />
                </div>
              )}
              <CardTitle className="text-xl">
                {getLocalizedField(merchantBrand, "name")}
              </CardTitle>
            </div>
          </CardHeader>
          <CardContent>
            {(merchantBrand.intro_zh || merchantBrand.intro_en || merchantBrand.intro_pt) && (
              <div
                className="text-sm text-muted-foreground line-clamp-3 mb-4 prose prose-sm max-w-none [&_p]:m-0 [&_*]:text-muted-foreground"
                dangerouslySetInnerHTML={{
                  __html: getLocalizedField(merchantBrand, "intro") || "",
                }}
              />
            )}
            <BrandFormDialog
              brand={merchantBrand}
              trigger={
                <Button className="w-full">
                  {t("common.edit")}
                </Button>
              }
            />
          </CardContent>
        </Card>
      ) : (
        <Card>
          <CardContent className="py-12 text-center">
            <Building2 className="mx-auto h-12 w-12 text-muted-foreground/50 mb-4" />
            <p className="text-muted-foreground mb-4">
              {t("merchant.brand.empty", "您还没有创建品牌")}
            </p>
            <BrandFormDialog
              trigger={
                <Button>
                  {t("merchant.brand.create", "创建品牌")}
                </Button>
              }
              onSuccess={(brandId) => {
                if (brandId) {
                  linkBrandToRestaurants.mutate(brandId);
                }
              }}
            />
          </CardContent>
        </Card>
      )}
    </div>
  );
};

export default MerchantBrand;
